import copy
import gzip
import inspect
import logging
import threading
import zlib
from functools import wraps
from hashlib import sha256
from typing import Any, Dict, Literal, Optional

import cloudpickle
import pydantic
import ujson
from cachetools import LRUCache, TTLCache
from diskcache import FanoutCache

logger = logging.getLogger(__name__)

_CACHE_MAGIC = b"DSPC"
_CODEC_NONE = b"\x00"
_CODEC_GZIP = b"\x01"
_CODEC_ZLIB = b"\x02"


class Cache:
    """DSPy Cache

    `Cache` provides 2 levels of caching (in the given order):
        1. In-memory cache - implemented with cachetools.LRUCache
        2. On-disk cache - implemented with diskcache.FanoutCache
    """

    def __init__(
        self,
        enable_disk_cache: bool,
        enable_memory_cache: bool,
        disk_cache_dir: str,
        disk_size_limit_bytes: Optional[int] = 1024 * 1024 * 10,
        memory_max_entries: Optional[int] = 1000000,
        ttl: Optional[int] = None,
        compress: Optional[Literal["gzip", "zlib"]] = None,
        cull_limit: Optional[int] = None,
        eviction_policy: Optional[str] = None,
    ):
